import{_ as h,o as a,c as t,a0 as o}from"./chunks/framework.jwovEGr5.js";const d=JSON.parse('{"title":"Kế toán","description":"","frontmatter":{"title":"Kế toán"},"headers":[],"relativePath":"accounts.md","filePath":"accounts.md"}'),i={name:"accounts.md"};function c(e,n,u,r,l,g){return a(),t("div",null,[...n[0]||(n[0]=[o('<h1 id="ke-toan" tabindex="-1">Kế toán <a class="header-anchor" href="#ke-toan" aria-label="Permalink to &quot;Kế toán&quot;">​</a></h1><h2 id="tong-quan" tabindex="-1">Tổng quan <a class="header-anchor" href="#tong-quan" aria-label="Permalink to &quot;Tổng quan&quot;">​</a></h2><p>Kế toán là trung tâm của hệ thống ABNERP. Mọi hoạt động kinh tế phát sinh trong doanh nghiệp — từ bán hàng, mua hàng, sản xuất đến quản lý nhân sự — đều được phản ánh đầy đủ và chính xác qua mô-đun Kế toán. Đây là nguồn dữ liệu tin cậy cho các báo cáo tài chính, giúp ban lãnh đạo đưa ra quyết định kịp thời.</p><h2 id="ba-giao-dich-chinh" tabindex="-1">Ba giao dịch chính <a class="header-anchor" href="#ba-giao-dich-chinh" aria-label="Permalink to &quot;Ba giao dịch chính&quot;">​</a></h2><p>Mô-đun Kế toán trong ABNERP xoay quanh ba loại giao dịch cốt lõi:</p><h3 id="_1-hoa-đon-ban-hang-sales-invoice" tabindex="-1">1. Hóa đơn Bán hàng (Sales Invoice) <a class="header-anchor" href="#_1-hoa-đon-ban-hang-sales-invoice" aria-label="Permalink to &quot;1. Hóa đơn Bán hàng (Sales Invoice)&quot;">​</a></h3><p>Ghi nhận doanh thu và công nợ phải thu từ khách hàng. Khi phát hành hóa đơn bán hàng, hệ thống tự động:</p><ul><li>Ghi nhận doanh thu vào tài khoản tương ứng</li><li>Cập nhật công nợ phải thu khách hàng</li><li>Giảm hàng tồn kho (đối với hàng hóa)</li><li>Tính toán và hạch toán thuế giá trị gia tăng (VAT)</li></ul><h3 id="_2-hoa-đon-mua-hang-purchase-invoice" tabindex="-1">2. Hóa đơn Mua hàng (Purchase Invoice) <a class="header-anchor" href="#_2-hoa-đon-mua-hang-purchase-invoice" aria-label="Permalink to &quot;2. Hóa đơn Mua hàng (Purchase Invoice)&quot;">​</a></h3><p>Ghi nhận chi phí mua hàng và công nợ phải trả cho nhà cung cấp. Khi nhập hóa đơn mua hàng:</p><ul><li>Tăng giá trị hàng tồn kho hoặc ghi nhận chi phí</li><li>Cập nhật công nợ phải trả nhà cung cấp</li><li>Hạch toán thuế GTGT đầu vào được khấu trừ</li></ul><h3 id="_3-but-toan-ke-toan-journal-entry" tabindex="-1">3. Bút toán Kế toán (Journal Entry) <a class="header-anchor" href="#_3-but-toan-ke-toan-journal-entry" aria-label="Permalink to &quot;3. Bút toán Kế toán (Journal Entry)&quot;">​</a></h3><p>Dùng để ghi nhận các giao dịch không thuộc hai loại trên, như:</p><ul><li>Điều chỉnh cuối kỳ (khấu hao, dự phòng, phân bổ)</li><li>Kết chuyển lãi/lỗ</li><li>Chuyển tiền giữa các tài khoản ngân hàng, quỹ tiền mặt</li><li>Ghi nhận các khoản vay, góp vốn, chi phí trả trước</li></ul><h2 id="cac-chu-đe-lien-quan" tabindex="-1">Các chủ đề liên quan <a class="header-anchor" href="#cac-chu-đe-lien-quan" aria-label="Permalink to &quot;Các chủ đề liên quan&quot;">​</a></h2><p>Mô-đun Kế toán bao gồm nhiều chức năng quan trọng:</p><h3 id="so-đo-tai-khoan" tabindex="-1">Sơ đồ Tài khoản <a class="header-anchor" href="#so-đo-tai-khoan" aria-label="Permalink to &quot;Sơ đồ Tài khoản&quot;">​</a></h3><p>Hệ thống tài khoản kế toán được tổ chức theo cấu trúc phân cấp, bao gồm các nhóm: Tài sản, Nợ phải trả, Vốn chủ sở hữu, Doanh thu, Chi phí. Xem thêm tại <a href="/abnerp/chart-of-accounts.html">Sơ đồ Tài khoản</a>.</p><h3 id="so-du-đau-ky" tabindex="-1">Số dư Đầu kỳ <a class="header-anchor" href="#so-du-đau-ky" aria-label="Permalink to &quot;Số dư Đầu kỳ&quot;">​</a></h3><p>Cho phép nhập số dư ban đầu cho các tài khoản khi bắt đầu sử dụng ABNERP. Hỗ trợ nhập số dư cho cả tài khoản tổng hợp và chi tiết (công nợ khách hàng, nhà cung cấp, hàng tồn kho).</p><h3 id="thue" tabindex="-1">Thuế <a class="header-anchor" href="#thue" aria-label="Permalink to &quot;Thuế&quot;">​</a></h3><p>ABNERP hỗ trợ nhiều loại thuế khác nhau:</p><ul><li>Thuế GTGT (VAT) đầu ra và đầu vào</li><li>Thuế thu nhập doanh nghiệp</li><li>Thuế thu nhập cá nhân (TNCN)</li><li>Thuế nhà thầu, thuế xuất nhập khẩu</li><li>Tự động tính toán trên hóa đơn và báo cáo thuế</li></ul><h3 id="thanh-toan-truoc" tabindex="-1">Thanh toán trước <a class="header-anchor" href="#thanh-toan-truoc" aria-label="Permalink to &quot;Thanh toán trước&quot;">​</a></h3><p>Cho phép nhận tiền đặt cọc từ khách hàng hoặc trả trước cho nhà cung cấp, sau đó đối trừ tự động khi phát hành hóa đơn.</p><h3 id="ngan-sach" tabindex="-1">Ngân sách <a class="header-anchor" href="#ngan-sach" aria-label="Permalink to &quot;Ngân sách&quot;">​</a></h3><p>ABNERP giúp lập và theo dõi ngân sách cho từng tài khoản, từng dự án hoặc toàn công ty. Hệ thống có thể cảnh báo hoặc chặn giao dịch vượt ngân sách.</p><h3 id="quan-ly-đang-ky" tabindex="-1">Quản lý Đăng ký <a class="header-anchor" href="#quan-ly-đang-ky" aria-label="Permalink to &quot;Quản lý Đăng ký&quot;">​</a></h3><p>Quản lý các khoản thu định kỳ (subscription) như phí dịch vụ, bảo trì, cho thuê — tự động tạo hóa đơn theo chu kỳ (hàng tháng, quý, năm).</p><h2 id="video-huong-dan" tabindex="-1">Video hướng dẫn <a class="header-anchor" href="#video-huong-dan" aria-label="Permalink to &quot;Video hướng dẫn&quot;">​</a></h2><ul><li><a href="https://www.youtube.com/watch?v=example1" target="_blank" rel="noreferrer">Giới thiệu mô-đun Kế toán ABNERP</a></li><li><a href="https://www.youtube.com/watch?v=example2" target="_blank" rel="noreferrer">Hướng dẫn tạo Hóa đơn Bán hàng</a></li><li><a href="https://www.youtube.com/watch?v=example3" target="_blank" rel="noreferrer">Hướng dẫn tạo Bút toán Kế toán</a></li><li><a href="https://www.youtube.com/watch?v=example4" target="_blank" rel="noreferrer">Lập báo cáo tài chính trên ABNERP</a></li></ul>',31)])])}const s=h(i,[["render",c]]);export{d as __pageData,s as default};
